template.script:
// Configuration Firebase
const firebaseConfig = {
apiKey: "AIzaSyCbPwjcyqE4Wa2eW9_uL7UxJesbhQ-zB_U",
authDomain: "sierck-inventory.firebaseapp.com",
databaseURL: "https://sierck-inventory-default-rtdb.europe-west1.firebasedatabase.app",
projectId: "sierck-inventory",
storageBucket: "sierck-inventory.firebasestorage.app",
messagingSenderId: "911920477735",
appId: "1:911920477735:web:16e7fb063cee32a8468002",
measurementId: "G-PZTQEXD5NX"
};

firebase.initializeApp(firebaseConfig);

function showError(message) {
const errorDiv = document.getElementById('error-message');
if (errorDiv) {
    errorDiv.textContent = message;
    errorDiv.style.display = 'block';
}
}

function hideError() {
const errorDiv = document.getElementById('error-message');
if (errorDiv) {
    errorDiv.style.display = 'none';
}
}

function showLoader() {
const loginForm = document.getElementById('login-form');
const loader = document.getElementById('loader');
if (loginForm) loginForm.style.display = 'none';
if (loader) loader.style.display = 'block';
}

function hideLoader() {
const loginForm = document.getElementById('login-form');
const loader = document.getElementById('loader');
if (loginForm) loginForm.style.display = 'block';
if (loader) loader.style.display = 'none';
}

function authenticateWithOdoo(idToken) {
fetch('/my/firebase/auth', {
method: 'POST',
headers: {
'Content-Type': 'application/json',
},
body: JSON.stringify({
jsonrpc: '2.0',
method: 'call',
params: {
id_token: idToken
}
})
})
.then(response => response.json())
.then(data => {
if (data.result && data.result.success) {
window.location.href = data.result.redirect_url;
} else {
hideLoader();
showError('Erreur d\'authentification: ' + (data.result.error || 'Erreur inconnue'));
}
})
.catch(error => {
console.error('Error:', error);
hideLoader();
showError('Erreur de connexion au serveur');
});
}

// Attendre le chargement du DOM pour les event listeners
document.addEventListener('DOMContentLoaded', function() {
// Connexion avec email/password
const loginBtn = document.getElementById('login-btn');
if (loginBtn) {
    loginBtn.addEventListener('click', function() {
    hideError();
    const email = document.getElementById('email').value;
    const password = document.getElementById('password').value;

    if (!email || !password) {
    showError('Veuillez remplir tous les champs');
    return;
    }

    showLoader();

    firebase.auth().signInWithEmailAndPassword(email, password)
    .then((userCredential) => {
    return userCredential.user.getIdToken();
    })
    .then((idToken) => {
    authenticateWithOdoo(idToken);
    })
    .catch((error) => {
    hideLoader();
    let errorMessage = 'Erreur de connexion';
    switch(error.code) {
    case 'auth/wrong-password':
    case 'auth/invalid-credential':
    case 'auth/invalid-login-credentials':
    errorMessage = 'Email ou mot de passe incorrect';
    break;
    case 'auth/user-not-found':
    errorMessage = 'Aucun compte trouvé avec cet email';
    break;
    case 'auth/invalid-email':
    errorMessage = 'Email invalide';
    break;
    case 'auth/user-disabled':
    errorMessage = 'Ce compte a été désactivé';
    break;
    case 'auth/too-many-requests':
    errorMessage = 'Trop de tentatives. Veuillez réessayer plus tard.';
    break;
    default:
    errorMessage = 'Erreur de connexion. Veuillez vérifier vos identifiants.';
    }
    showError(errorMessage);
    });
    });
}

// Connexion avec Google
const googleLoginBtn = document.getElementById('google-login-btn');
if (googleLoginBtn) {
    googleLoginBtn.addEventListener('click', function() {
    hideError();
    showLoader();

    const provider = new firebase.auth.GoogleAuthProvider();
    firebase.auth().signInWithPopup(provider)
    .then((userCredential) => {
    return userCredential.user.getIdToken();
    })
    .then((idToken) => {
    authenticateWithOdoo(idToken);
    })
    .catch((error) => {
    hideLoader();
    if (error.code !== 'auth/popup-closed-by-user') {
    showError('Erreur de connexion avec Google: ' + error.message);
    }
    });
    });
}

// Permettre la connexion avec la touche Entrée
const passwordInputEnter = document.getElementById('password');
if (passwordInputEnter) {
    passwordInputEnter.addEventListener('keypress', function(e) {
        if (e.key === 'Enter') {
            document.getElementById('login-btn').click();
        }
    });
}

// Afficher/Masquer le mot de passe (connexion)
const togglePasswordBtn = document.getElementById("toggle-password");
if (togglePasswordBtn) {
    togglePasswordBtn.addEventListener("click", function() {
        const passwordInput = document.getElementById("password");
        const icon = this.querySelector("i");

        if (passwordInput && icon) {
            if (passwordInput.type === "password") {
                passwordInput.type = "text";
                icon.classList.remove("fa-eye");
                icon.classList.add("fa-eye-slash");
            } else {
                passwordInput.type = "password";
                icon.classList.remove("fa-eye-slash");
                icon.classList.add("fa-eye");
            }
        }
    });
}

// Afficher/Masquer le mot de passe (inscription)
const togglePasswordRegister = document.getElementById("toggle-password-register");
if (togglePasswordRegister) {
    togglePasswordRegister.addEventListener("click", function() {
        const passwordInput = document.getElementById("password");
        const icon = this.querySelector("i");

        if (passwordInput && icon) {
            if (passwordInput.type === "password") {
                passwordInput.type = "text";
                icon.classList.remove("fa-eye");
                icon.classList.add("fa-eye-slash");
            } else {
                passwordInput.type = "password";
                icon.classList.remove("fa-eye-slash");
                icon.classList.add("fa-eye");
            }
        }
    });
}

// Afficher/Masquer la confirmation du mot de passe
const togglePasswordConfirm = document.getElementById("toggle-password-confirm");
if (togglePasswordConfirm) {
    togglePasswordConfirm.addEventListener("click", function() {
        const passwordInput = document.getElementById("password_confirm");
        const icon = this.querySelector("i");

        if (passwordInput && icon) {
            if (passwordInput.type === "password") {
                passwordInput.type = "text";
                icon.classList.remove("fa-eye");
                icon.classList.add("fa-eye-slash");
            } else {
                passwordInput.type = "password";
                icon.classList.remove("fa-eye-slash");
                icon.classList.add("fa-eye");
            }
        }
    });
}
});

// Configuration Firebase
const firebaseConfig = {
    apiKey: "AIzaSyCbPwjcyqE4Wa2eW9_uL7UxJesbhQ-zB_U",
    authDomain: "sierck-inventory.firebaseapp.com",
    databaseURL: "https://sierck-inventory-default-rtdb.europe-west1.firebasedatabase.app",
    projectId: "sierck-inventory",
    storageBucket: "sierck-inventory.firebasestorage.app",
    messagingSenderId: "911920477735",
    appId: "1:911920477735:web:16e7fb063cee32a8468002",
    measurementId: "G-PZTQEXD5NX"
};

firebase.initializeApp(firebaseConfig);

function showError(message) {
    const errorDiv = document.getElementById('error-message');
    errorDiv.textContent = message;
    errorDiv.style.display = 'block';
}

function hideError() {
    document.getElementById('error-message').style.display = 'none';
}

function showLoader() {
    document.getElementById('register-form').style.display = 'none';
    document.getElementById('loader').style.display = 'block';
}

function hideLoader() {
    document.getElementById('register-form').style.display = 'block';
    document.getElementById('loader').style.display = 'none';
}

function authenticateWithOdoo(idToken, userData) {
    fetch('/my/firebase/auth', {
        method: 'POST',
        headers: {
            'Content-Type': 'application/json',
        },
        body: JSON.stringify({
            jsonrpc: '2.0',
            method: 'call',
            params: {
                id_token: idToken,
                user_data: userData
            }
        })
    })
    .then(response => response.json())
    .then(data => {
        if (data.result && data.result.success) {
            // Rediriger vers la page de création d'UO
            window.location.href = '/my/firebase/uo/create?success=registered';
        } else {
            hideLoader();
            showError('Erreur d\'authentification: ' + (data.result.error || 'Erreur inconnue'));
        }
    })
    .catch(error => {
        console.error('Error:', error);
        hideLoader();
        showError('Erreur de connexion au serveur');
    });
}

// Inscription avec email/password
document.getElementById('register-btn').addEventListener('click', function() {
    hideError();
    const name = document.getElementById('name').value.trim();
    const email = document.getElementById('email').value.trim();
    const password = document.getElementById('password').value;
    const passwordConfirm = document.getElementById('password_confirm').value;

    // Validation
    if (!name || !email || !password || !passwordConfirm) {
        showError('Veuillez remplir tous les champs');
        return;
    }

    if (password.length < 6) {
        showError('Le mot de passe doit contenir au moins 6 caractères');
        return;
    }

    if (password !== passwordConfirm) {
        showError('Les mots de passe ne correspondent pas');
        return;
    }

    showLoader();

    // Créer le compte Firebase
    firebase.auth().createUserWithEmailAndPassword(email, password)
        .then((userCredential) => {
            // Mettre à jour le profil avec le nom
            return userCredential.user.updateProfile({
                displayName: name
            }).then(() => {
                return userCredential.user.getIdToken();
            }).then((idToken) => {
                authenticateWithOdoo(idToken, {
                    name: name,
                    email: email
                });
            });
        })
        .catch((error) => {
            hideLoader();
            let errorMessage = 'Erreur lors de la création du compte';
            switch(error.code) {
                case 'auth/email-already-in-use':
                    errorMessage = 'Cet email est déjà utilisé';
                    break;
                case 'auth/invalid-email':
                    errorMessage = 'Email invalide';
                    break;
                case 'auth/weak-password':
                    errorMessage = 'Mot de passe trop faible (minimum 6 caractères)';
                    break;
                case 'auth/operation-not-allowed':
                    errorMessage = 'Cette opération n\'est pas autorisée';
                    break;
                case 'auth/too-many-requests':
                    errorMessage = 'Trop de tentatives. Veuillez réessayer plus tard.';
                    break;
                default:
                    errorMessage = 'Erreur lors de la création du compte. Veuillez réessayer.';
            }
            showError(errorMessage);
        });

    // Permettre l'inscription avec la touche Entrée
    const passwordConfirm = document.getElementById('password_confirm');
    if (passwordConfirm) {
        passwordConfirm.addEventListener('keypress', function(e) {
            if (e.key === 'Enter') {
                document.getElementById('register-btn').click();
            }
        });
    }

    // Indicateur de force du mot de passe
    function checkPasswordStrength(password) {
        let strength = 0;
        const strengthBar = document.getElementById('strength-bar');
        const strengthText = document.getElementById('strength-text');

        if (!password || !strengthBar || !strengthText) {
            return;
        }

        if (!password) {
            const passwordStrength = document.getElementById('password-strength');
            if (passwordStrength) {
                passwordStrength.style.display = 'none';
            }
            return;
        }

        const passwordStrength = document.getElementById('password-strength');
        if (passwordStrength) {
            passwordStrength.style.display = 'block';
        }

        // Vérifications
        if (password.length >= 6) strength += 20;
        if (password.length >= 10) strength += 20;
        if (/[a-z]/.test(password)) strength += 15;
        if (/[A-Z]/.test(password)) strength += 15;
        if (/[0-9]/.test(password)) strength += 15;
        if (/[^a-zA-Z0-9]/.test(password)) strength += 15;

        // Limiter à 100
        strength = Math.min(strength, 100);

        // Mettre à jour la barre
        strengthBar.style.width = strength + '%';

        // Mettre à jour la couleur et le texte
        if (strength < 30) {
            strengthBar.className = 'progress-bar bg-danger';
            strengthText.textContent = 'Très faible';
        } else if (strength < 50) {
            strengthBar.className = 'progress-bar bg-warning';
            strengthText.textContent = 'Faible';
        } else if (strength < 70) {
            strengthBar.className = 'progress-bar bg-info';
            strengthText.textContent = 'Moyen';
        } else if (strength < 90) {
            strengthBar.className = 'progress-bar bg-success';
            strengthText.textContent = 'Bon';
        } else {
            strengthBar.className = 'progress-bar bg-success';
            strengthText.textContent = 'Très bon';
        }
    }

    // Écouter les modifications du mot de passe
    const passwordInputRegister = document.getElementById('password');
    if (passwordInputRegister) {
        passwordInputRegister.addEventListener('input', function() {
            checkPasswordStrength(this.value);
        });
    }
});

t.script:
(function () {
    var confirmInput = document.getElementById('confirm_uo_name');
    var submitBtn = document.getElementById('btnConfirmCancel');
    var reasonSelect = document.getElementById('cancel_reason');

    function checkReady() {
        var nameOk = confirmInput && confirmInput.value.trim() === confirmInput.dataset.uoName;
        var reasonOk = reasonSelect && reasonSelect.value !== '';
        if (submitBtn) {
            submitBtn.disabled = !(nameOk && reasonOk);
        }
    }

    if (confirmInput) { confirmInput.addEventListener('input', checkReady); }
    if (reasonSelect) { reasonSelect.addEventListener('change', checkReady); }

    // Gestion "Autre" : remplacer le select par le textarea
    var otherTextarea = document.getElementById('cancel_reason_other');
    if (reasonSelect) {
        reasonSelect.addEventListener('change', function () {
            if (this.value === 'Autre') {
                this.removeAttribute('name');
                if (otherTextarea) { otherTextarea.setAttribute('name', 'cancel_reason'); }
            } else {
                this.setAttribute('name', 'cancel_reason');
                if (otherTextarea) { otherTextarea.removeAttribute('name'); }
            }
            checkReady();
        });
    }
})();

                // Attendre que jQuery soit chargé
                (function waitForJQuery() {
                    if (typeof jQuery === 'undefined') {
                        setTimeout(waitForJQuery, 50);
                        return;
                    }

                    // jQuery est maintenant disponible, utiliser $ comme alias
                    var $ = jQuery;
                    var uoId = ;
                    var vehicleId = ;
                    var currentCategoryId = null;
                    var currentGroupId = null;
                    var pending = { categories: {}, items: {}, groups: {} };
                    var isDirty = false;

                    // ========== Ouvrir/fermer un modal en CSS pur (pas Bootstrap JS) ==========
                    function showModal(id) {
                        var el = document.getElementById(id);
                        if (!el) return;
                        el.style.display = 'block';
                        el.classList.add('show');
                        document.body.classList.add('modal-open');
                        // backdrop
                        var bd = document.createElement('div');
                        bd.className = 'modal-backdrop fade show';
                        bd.id = id + '-backdrop';
                        document.body.appendChild(bd);
                        // focus premier input
                        var inp = el.querySelector('input');
                        if (inp) setTimeout(function() { inp.focus(); }, 100);
                    }
                    function hideModal(id) {
                        var el = document.getElementById(id);
                        if (!el) return;
                        el.style.display = 'none';
                        el.classList.remove('show');
                        document.body.classList.remove('modal-open');
                        var bd = document.getElementById(id + '-backdrop');
                        if (bd) bd.remove();
                    }

                    // Fermer avec la croix ou "Annuler"
                    $(document).on('click', '.modal-close-btn', function() {
                        var id = $(this).data('modal');
                        hideModal(id);
                    });

                    // Fermer en cliquant sur le backdrop
                    $(document).on('click', '.modal-backdrop', function() {
                        var shown = document.querySelector('.modal.show');
                        if (shown) hideModal(shown.id);
                    });

                    function markDirty() {
                        isDirty = true;
                        $('#btn-sync-firebase').addClass('btn-warning').removeClass('btn-primary');
                        $('#dirty-badge').show();
                    }

                    function showMessage(message, type) {
                        var alertClass = type === 'success' ? 'alert-success' : 'alert-danger';
                        var icon = type === 'success' ? 'fa-check-circle' : 'fa-exclamation-triangle';
                        $('#message-zone').html(
                            '
' +
                            ' ' + message +
                            '' +
                            ''
                        );
                        setTimeout(function() { $('#message-zone .alert').remove(); }, 5000);
                    }

                    // Sortable catégories
                    var productsContainer = document.getElementById('products-container');
                    if (productsContainer) {
                        new Sortable(productsContainer, {
                            handle: '.product-card .card-header .drag-handle',
                            animation: 150,
                            onEnd: function() { markDirty(); }
                        });
                    }
                    // Sortable items
                    document.querySelectorAll('.items-container').forEach(function(container) {
                        var lg = container.querySelector('.list-group');
                        if (lg) new Sortable(lg, { handle: '.drag-handle', animation: 150, onEnd: function() { markDirty(); } });
                    });

                    // ========== ÉDITION INLINE — stockage local uniquement ==========
                    $(document).on('input blur', '.category-label-input', function() {
                        var id = $(this).data('product-id'), val = $(this).val().trim();
                        if (val) { pending.categories[id] = { label: val }; markDirty(); }
                    });
                    $(document).on('input blur', '.item-description-input', function() {
                        var id = $(this).data('item-id'), val = $(this).val().trim();
                        if (val) { if (!pending.items[id]) pending.items[id] = {}; pending.items[id].description = val; markDirty(); }
                    });
                    $(document).on('input change', '.item-quantity-input', function() {
                        var id = $(this).data('item-id'), val = parseInt($(this).val());
                        if (val >= 1) { if (!pending.items[id]) pending.items[id] = {}; pending.items[id].quantity = val; markDirty(); }
                    });
                    $(document).on('input blur', '.group-label-input', function() {
                        var id = $(this).data('group-id'), val = $(this).val().trim();
                        if (val) { pending.groups[id] = { label: val }; markDirty(); }
                    });
                    $(document).on('keypress', '.category-label-input, .item-description-input, .group-label-input', function(e) {
                        if (e.which === 13) $(this).blur();
                    });

                    // ========== AJOUTER CATÉGORIE ==========
                    $('#btn-add-category').on('click', function() {
                        $('#category-label').val('');
                        showModal('categoryModal');
                    });
                    $('#btn-save-category').on('click', function() {
                        var label = $('#category-label').val().trim();
                        if (!label) { alert('Veuillez entrer un nom de catégorie'); return; }
                        hideModal('categoryModal');
                        $.ajax({
                            url: '/my/firebase/uo/' + uoId + '/vehicle/' + vehicleId + '/product/add',
                            type: 'POST', contentType: 'application/json',
                            data: JSON.stringify({ jsonrpc: '2.0', method: 'call', params: { label: label } }),
                            dataType: 'json',
                            success: function(data) {
                                if (data.result && data.result.success) { showMessage('Catégorie ajoutée!', 'success'); setTimeout(function() { location.reload(); }, 800); }
                                else showMessage('Erreur: ' + (data.result ? data.result.error : '?'), 'error');
                            },
                            error: function() { showMessage('Erreur de communication', 'error'); }
                        });
                    });

                    // ========== SUPPRIMER CATÉGORIE ==========
                    $(document).on('click', '.btn-delete-category', function() {
                        if (!confirm('Supprimer cette catégorie et tous ses items ?')) return;
                        var productId = $(this).data('product-id');
                        $.ajax({
                            url: '/my/firebase/uo/' + uoId + '/vehicle/' + vehicleId + '/product/' + productId + '/delete',
                            type: 'POST', contentType: 'application/json',
                            data: JSON.stringify({ jsonrpc: '2.0', method: 'call', params: {} }),
                            dataType: 'json',
                            success: function(data) {
                                if (data.result && data.result.success) { showMessage('Catégorie supprimée!', 'success'); setTimeout(function() { location.reload(); }, 800); }
                                else showMessage('Erreur: ' + (data.result ? data.result.error : '?'), 'error');
                            },
                            error: function() { showMessage('Erreur de communication', 'error'); }
                        });
                    });

                    // ========== AJOUTER GROUPE ==========
                    $(document).on('click', '.btn-add-group', function() {
                        currentCategoryId = $(this).data('product-id');
                        $('#group-label').val('');
                        showModal('groupModal');
                    });
                    $('#btn-save-group').on('click', function() {
                        var label = $('#group-label').val().trim();
                        if (!label) { alert('Veuillez entrer un nom de sous-section'); return; }
                        hideModal('groupModal');
                        $.ajax({
                            url: '/my/firebase/uo/' + uoId + '/vehicle/' + vehicleId + '/product/' + currentCategoryId + '/group/add',
                            type: 'POST', contentType: 'application/json',
                            data: JSON.stringify({ jsonrpc: '2.0', method: 'call', params: { label: label } }),
                            dataType: 'json',
                            success: function(data) {
                                if (data.result && data.result.success) { showMessage('Sous-section ajoutée!', 'success'); setTimeout(function() { location.reload(); }, 800); }
                                else showMessage('Erreur: ' + (data.result ? data.result.error : '?'), 'error');
                            },
                            error: function() { showMessage('Erreur de communication', 'error'); }
                        });
                    });

                    // ========== SUPPRIMER GROUPE ==========
                    $(document).on('click', '.btn-delete-group', function() {
                        if (!confirm('Supprimer cette sous-section et tous ses sous-items ?')) return;
                        var groupId = $(this).data('group-id');
                        $.ajax({
                            url: '/my/firebase/uo/' + uoId + '/vehicle/' + vehicleId + '/group/' + groupId + '/delete',
                            type: 'POST', contentType: 'application/json',
                            data: JSON.stringify({ jsonrpc: '2.0', method: 'call', params: {} }),
                            dataType: 'json',
                            success: function(data) {
                                if (data.result && data.result.success) { showMessage('Sous-section supprimée!', 'success'); setTimeout(function() { location.reload(); }, 800); }
                                else showMessage('Erreur: ' + (data.result ? data.result.error : '?'), 'error');
                            },
                            error: function() { showMessage('Erreur de communication', 'error'); }
                        });
                    });

                    // ========== AJOUTER SOUS-ITEM ==========
                    $(document).on('click', '.btn-add-subitem', function() {
                        currentGroupId = $(this).data('group-id');
                        $('#subitem-description').val('');
                        $('#subitem-quantity').val(1);
                        showModal('subitemModal');
                    });
                    $('#btn-save-subitem').on('click', function() {
                        var description = $('#subitem-description').val().trim();
                        var quantity = parseInt($('#subitem-quantity').val());
                        if (!description) { alert('Veuillez entrer une description'); return; }
                        hideModal('subitemModal');
                        $.ajax({
                            url: '/my/firebase/uo/' + uoId + '/vehicle/' + vehicleId + '/group/' + currentGroupId + '/item/add',
                            type: 'POST', contentType: 'application/json',
                            data: JSON.stringify({ jsonrpc: '2.0', method: 'call', params: { description: description, quantity: quantity } }),
                            dataType: 'json',
                            success: function(data) {
                                if (data.result && data.result.success) { showMessage('Sous-item ajouté!', 'success'); setTimeout(function() { location.reload(); }, 800); }
                                else showMessage('Erreur: ' + (data.result ? data.result.error : '?'), 'error');
                            },
                            error: function() { showMessage('Erreur de communication', 'error'); }
                        });
                    });

                    // ========== AJOUTER ITEM DIRECT ==========
                    $(document).on('click', '.btn-add-item', function() {
                        currentCategoryId = $(this).data('product-id');
                        $('#item-description').val('');
                        $('#item-quantity').val(1);
                        showModal('itemModal');
                    });
                    $('#btn-save-item').on('click', function() {
                        var description = $('#item-description').val().trim();
                        var quantity = parseInt($('#item-quantity').val());
                        if (!description) { alert('Veuillez entrer une description'); return; }
                        hideModal('itemModal');
                        $.ajax({
                            url: '/my/firebase/uo/' + uoId + '/vehicle/' + vehicleId + '/product/' + currentCategoryId + '/item/add',
                            type: 'POST', contentType: 'application/json',
                            data: JSON.stringify({ jsonrpc: '2.0', method: 'call', params: { description: description, quantity: quantity } }),
                            dataType: 'json',
                            success: function(data) {
                                if (data.result && data.result.success) { showMessage('Item ajouté!', 'success'); setTimeout(function() { location.reload(); }, 800); }
                                else showMessage('Erreur: ' + (data.result ? data.result.error : '?'), 'error');
                            },
                            error: function() { showMessage('Erreur de communication', 'error'); }
                        });
                    });

                    // ========== SUPPRIMER ITEM ==========
                    $(document).on('click', '.btn-delete-item', function() {
                        if (!confirm('Supprimer cet item ?')) return;
                        var itemId = $(this).data('item-id');
                        $.ajax({
                            url: '/my/firebase/uo/' + uoId + '/vehicle/' + vehicleId + '/item/' + itemId + '/delete',
                            type: 'POST', contentType: 'application/json',
                            data: JSON.stringify({ jsonrpc: '2.0', method: 'call', params: {} }),
                            dataType: 'json',
                            success: function(data) {
                                if (data.result && data.result.success) { showMessage('Item supprimé!', 'success'); setTimeout(function() { location.reload(); }, 800); }
                                else showMessage('Erreur: ' + (data.result ? data.result.error : '?'), 'error');
                            },
                            error: function() { showMessage('Erreur de communication', 'error'); }
                        });
                    });

                    // ========== SYNCHRONISER : flush pending → Odoo → Firebase ==========
                    $('#btn-sync-firebase').on('click', function() {
                        var btn = $(this);
                        btn.prop('disabled', true).html(' Synchronisation...');

                        var flushPromises = [];

                        Object.keys(pending.categories).forEach(function(id) {
                            flushPromises.push($.ajax({ url: '/my/firebase/uo/' + uoId + '/vehicle/' + vehicleId + '/product/' + id + '/update', type: 'POST', contentType: 'application/json', data: JSON.stringify({ jsonrpc: '2.0', method: 'call', params: pending.categories[id] }), dataType: 'json' }));
                        });
                        Object.keys(pending.items).forEach(function(id) {
                            flushPromises.push($.ajax({ url: '/my/firebase/uo/' + uoId + '/vehicle/' + vehicleId + '/item/' + id + '/update', type: 'POST', contentType: 'application/json', data: JSON.stringify({ jsonrpc: '2.0', method: 'call', params: pending.items[id] }), dataType: 'json' }));
                        });
                        Object.keys(pending.groups).forEach(function(id) {
                            flushPromises.push($.ajax({ url: '/my/firebase/uo/' + uoId + '/vehicle/' + vehicleId + '/group/' + id + '/update', type: 'POST', contentType: 'application/json', data: JSON.stringify({ jsonrpc: '2.0', method: 'call', params: pending.groups[id] }), dataType: 'json' }));
                        });
                        document.querySelectorAll('.product-card').forEach(function(card, i) {
                            flushPromises.push($.ajax({ url: '/my/firebase/uo/' + uoId + '/vehicle/' + vehicleId + '/product/' + card.dataset.productId + '/update', type: 'POST', contentType: 'application/json', data: JSON.stringify({ jsonrpc: '2.0', method: 'call', params: { sequence: (i + 1) * 10 } }), dataType: 'json' }));
                        });
                        document.querySelectorAll('.items-container').forEach(function(container) {
                            container.querySelectorAll('.item-row, .group-row').forEach(function(row, i) {
                                var itemId = parseInt(row.dataset.itemId || row.dataset.groupId);
                                if (itemId) flushPromises.push($.ajax({ url: '/my/firebase/uo/' + uoId + '/vehicle/' + vehicleId + '/item/' + itemId + '/update', type: 'POST', contentType: 'application/json', data: JSON.stringify({ jsonrpc: '2.0', method: 'call', params: { sequence: (i + 1) * 10 } }), dataType: 'json' }));
                            });
                        });

                        $.when.apply($, flushPromises.length ? flushPromises : [$.Deferred().resolve()]).always(function() {
                            pending = { categories: {}, items: {}, groups: {} };
                            isDirty = false;
                            $.ajax({
                                url: '/my/firebase/uo/' + uoId + '/vehicle/' + vehicleId + '/sync',
                                type: 'POST', contentType: 'application/json',
                                data: JSON.stringify({ jsonrpc: '2.0', method: 'call', params: {} }),
                                dataType: 'json',
                                success: function(data) {
                                    btn.prop('disabled', false).html(' Synchroniser avec Firebase');
                                    btn.removeClass('btn-warning').addClass('btn-primary');
                                    $('#dirty-badge').hide();
                                    if (data.result && data.result.success) showMessage('Synchronisation Firebase réussie!', 'success');
                                    else showMessage('Erreur: ' + (data.result ? data.result.error : '?'), 'error');
                                },
                                error: function() {
                                    btn.prop('disabled', false).html(' Synchroniser avec Firebase');
                                    showMessage('Erreur de communication', 'error');
                                }
                            });
                        });
                    });
                })();

function testReportingApi(btn) {
    var uoId = btn.getAttribute('data-uo-id');
    var zone = document.getElementById('api-response-zone');
    var content = document.getElementById('api-response-content');
    content.textContent = 'Chargement...';
    zone.style.display = 'block';
    fetch('/my/firebase/uo/' + uoId + '/reporting/api', {
        method: 'GET',
        headers: {
            'Content-Type': 'application/json',
            'X-Requested-With': 'XMLHttpRequest'
        }
    })
    .then(r => r.json())
    .then(data => {
        content.textContent = JSON.stringify(data, null, 2);
    })
    .catch(err => {
        content.textContent = 'Erreur : ' + err.message;
    });
}

document.addEventListener('DOMContentLoaded', function() {
    const accordionButtons = document.querySelectorAll('#policiesAccordion .policy-btn');
    const allCollapses = document.querySelectorAll('#policiesAccordion .policy-collapse');

    accordionButtons.forEach(function(button) {
        button.addEventListener('click', function() {
            // Le collapse correspondant est dans le même accordion-item
            const item = this.closest('.accordion-item');
            const targetElement = item ? item.querySelector('.policy-collapse') : null;
            if (!targetElement) return;

            const isOpen = targetElement.classList.contains('show');

            // Tout fermer
            allCollapses.forEach(function(c) { c.classList.remove('show'); });
            accordionButtons.forEach(function(b) {
                b.classList.add('collapsed');
                b.setAttribute('aria-expanded', 'false');
            });

            // Ouvrir celui-ci s'il était fermé
            if (!isOpen) {
                targetElement.classList.add('show');
                this.classList.remove('collapsed');
                this.setAttribute('aria-expanded', 'true');
            }
        });
    });
});
